import React from "react";
import { Modal, Row, Col, Card, Typography, theme, ConfigProvider, Tag } from "antd";
import EChart from "@/framework/components/Chart/EChart";
import { ZoneInfo, DensityLevel } from "../data/mockData";
import { useI18n } from "@/framework/i18n/hooks";

const { Text, Title } = Typography;
const { useToken } = theme;

interface Props {
  zones: ZoneInfo[];
  visible: boolean;
  onClose: () => void;
}

const FloorStatusModal: React.FC<Props> = ({ zones, visible, onClose }) => {
  const { token } = useToken();
  const { t } = useI18n(["dashboard"]);

  const floors = ["B1", "B2", "B3", "B4"];

  // Aggregate Data by Floor
  const floorStats = floors.map(f => {
    const floorZones = zones.filter(z => z.floor === f);
    const maxLevel = floorZones.length > 0 
      ? Math.max(...floorZones.map(z => z.avgLevel)) as DensityLevel 
      : 1 as DensityLevel;
    return { floor: f, level: maxLevel };
  });

  const totalMaxLevel = Math.max(...floorStats.map(s => s.level)) as DensityLevel;

  const levelColors: Record<number, string> = {
    1: token.colorSuccess,
    2: token.colorInfo,
    3: token.colorWarning,
    4: "#fa8c16",
    5: token.colorError
  };

  const levelLabels: Record<number, string> = {
    1: t("modal.safe"),
    2: t("modal.normal"),
    3: t("modal.caution"),
    4: t("modal.crowded"),
    5: t("modal.danger")
  };

  const getGaugeOption = (level: number) => ({
    series: [{
      type: "gauge",
      startAngle: 180, endAngle: 0,
      center: ["50%", "75%"], radius: "90%",
      axisLine: {
        lineStyle: {
          width: 15,
          color: [[0.2, levelColors[1]], [0.4, levelColors[2]], [0.6, levelColors[3]], [0.8, levelColors[4]], [1, levelColors[5]]]
        }
      },
      pointer: { show: true, length: "60%", width: 6, itemStyle: { color: "#fff", borderColor: levelColors[level], borderWidth: 1 } },
      axisTick: { show: false },
      splitLine: { show: false },
      axisLabel: { show: false }, // HTML 레이어에서 처리
      detail: { show: false },
      data: [{ value: (level * 20) - 10 }]
    }]
  });

  const cardBg = token.colorBgContainer;
  const textColor = token.colorText;

  return (
    <ConfigProvider
      theme={{
        token: {
          colorBgElevated: cardBg,
          colorBgContainer: cardBg,
        }
      }}
    >
      <Modal
        title={
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            <Title level={4} style={{ margin: 0, color: textColor, fontWeight: 800 }}>
              {t("modal.floor_status_title")}
            </Title>
          </div>
        }
        open={visible}
        onCancel={onClose}
        footer={null}
        width={720}
        centered
        styles={{ 
          mask: { backdropFilter: "blur(8px)", backgroundColor: "rgba(0,0,0,0.6)" },
          header: { background: "transparent", borderBottom: `1px solid ${token.colorBorderSecondary}`, padding: "20px 24px" },
          body: { background: "transparent", padding: "24px" }
        }}
      >
        <Row gutter={[20, 20]}>
          {floorStats.map(stat => (
            <Col span={6} key={stat.floor}>
              <Card 
                size="small" 
                variant="borderless" 
                style={{ background: token.colorBgLayout, borderRadius: 16, textAlign: "center", border: `1px solid ${token.colorBorderSecondary}40` }}
                bodyStyle={{ padding: "16px 12px" }}
              >
                <Tag color="blue" style={{ marginBottom: 12, borderRadius: 6, fontWeight: 700 }}>{stat.floor}</Tag>
                
                {/* Gauge Labels Row */}
                <div style={{ 
                  display: "flex", 
                  justifyContent: "space-between", 
                  fontSize: 10, 
                  fontWeight: 700, 
                  color: "#fff", 
                  padding: "0 4px", 
                  marginBottom: -15,
                  position: "relative",
                  zIndex: 2,
                  opacity: 0.9
                }}>
                  <span>{t("modal.safe")}</span>
                  <span>{t("modal.caution")}</span>
                  <span>{t("modal.danger")}</span>
                </div>

                <EChart option={getGaugeOption(stat.level)} style={{ height: 110, width: "100%" }} />

                <div style={{ marginTop: -10 }}>
                  <Tag 
                    color={stat.level >= 5 ? "error" : stat.level >= 4 ? "volcano" : stat.level >= 3 ? "warning" : "success"}
                    style={{ fontWeight: 800, fontSize: 13, borderRadius: 4 }}
                  >
                    {levelLabels[stat.level]}
                  </Tag>
                </div>
              </Card>
            </Col>
          ))}

          <Col span={24}>
            <div style={{ 
              marginTop: 16, 
              padding: "32px 24px", 
              background: totalMaxLevel >= 5 ? token.colorError + "20" : token.colorBgLayout,
              border: `2px solid ${totalMaxLevel >= 5 ? token.colorError : token.colorBorderSecondary}`,
              borderRadius: 20,
              textAlign: "center",
              boxShadow: totalMaxLevel >= 5 ? `0 0 30px ${token.colorError}30` : "none"
            }}>
              <div style={{ 
                fontSize: 68, 
                fontWeight: 900, 
                color: totalMaxLevel >= 5 ? token.colorError : textColor,
                letterSpacing: -2,
                marginBottom: 8,
                textShadow: totalMaxLevel >= 5 ? `0 0 15px ${token.colorError}80` : "none"
              }}>
                {totalMaxLevel >= 5 ? t("modal.total_danger") : t("modal.total_normal")}
              </div>
              <Text style={{ color: textColor, fontSize: 15, fontWeight: 500, opacity: 0.9 }}>
                {t("modal.total_status_desc")}
              </Text>
            </div>
          </Col>
        </Row>
      </Modal>
    </ConfigProvider>
  );
};

export default FloorStatusModal;
