import React, { useRef, useEffect, useState } from "react";
import { Stage, Layer, Text, Line, Rect, Image as KonvaImage } from "react-konva";
import { ZoneInfo, CameraInfo, LEVEL_MAP } from "../data/mockData";
import { Card, Empty, theme } from "antd";
import { LayoutOutlined } from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";

const { useToken } = theme;

interface Props {
  zones: ZoneInfo[];
  cameras: CameraInfo[];
  selectedZoneId?: string | null;
  selectedCameraId?: number | null;
  onZoneSelect: (id: string) => void;
  onCameraSelect: (id: number) => void;
  extra?: React.ReactNode;
}

const CrowdKonvaMap: React.FC<Props> = ({ 
  zones, 
  cameras, 
  selectedZoneId, 
  selectedCameraId,
  onZoneSelect,
  onCameraSelect,
  extra
}) => {
  const { token } = useToken();
  const { t } = useI18n(["dashboard"]);
  const containerRef = useRef<HTMLDivElement>(null);
  const [dimensions, setDimensions] = useState({ width: 800, height: 600 });
  const [mapImage, setMapImage] = useState<HTMLImageElement | null>(null);
  const [icons, setIcons] = useState<Record<string, HTMLImageElement>>({});
  const [hoveredCameraId, setHoveredCameraId] = useState<number | null>(null);

  // Responsive behavior
  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { width, height } = entry.contentRect;
        setDimensions({ width, height });
      }
    });
    observer.observe(containerRef.current);
    return () => observer.disconnect();
  }, []);

  // Load BG Image
  useEffect(() => {
    const img = new window.Image();
    img.src = `${import.meta.env.BASE_URL}assets/platforms/crowdsafe/map/station.webp`;
    img.onload = () => setMapImage(img);
  }, []);

  // Load Icons
  useEffect(() => {
    const statuses = ["normal", "warning", "inspection", "error"];
    const types = ["crowd", "humantraffic"];
    const loadedIcons: Record<string, HTMLImageElement> = {};
    let loadCount = 0;

    types.forEach(type => {
      statuses.forEach(status => {
        const img = new window.Image();
        const key = `${type}_${status}`;
        img.src = `${import.meta.env.BASE_URL}assets/platforms/crowdsafe/marker/${key}.png`;
        img.onload = () => {
          loadedIcons[key] = img;
          loadCount++;
          if (loadCount === statuses.length * types.length) setIcons({ ...loadedIcons });
        };
      });
    });
  }, []);

  const getStatusKey = (level: number) => {
    if (level <= 2) return "normal";
    if (level === 3) return "warning";
    if (level === 4) return "inspection";
    return "error";
  };

  // Scaling and Pan States
  const [stageScale, setStageScale] = useState<number>(1);
  const [stagePos, setStagePos] = useState({ x: 0, y: 0 });

  const baseW = 800;
  const baseH = 500;

  // Initialize scale with width-fit
  useEffect(() => {
    if (dimensions.width > 0) {
      const initScale = (dimensions.width - 20) / baseW;
      const offX = (dimensions.width - baseW * initScale) / 2;
      const offY = (dimensions.height - baseH * initScale) / 2;
      setStageScale(initScale);
      setStagePos({ x: offX, y: offY });
    }
  }, [dimensions]);

  const handleWheel = (e: any) => {
    e.evt.preventDefault();
    const scaleBy = 1.05;
    const stage = e.target.getStage();
    const oldScale = stage.scaleX();
    const pointer = stage.getPointerPosition();

    const mousePointTo = {
      x: (pointer.x - stage.x()) / oldScale,
      y: (pointer.y - stage.y()) / oldScale,
    };

    const newScale = e.evt.deltaY < 0 ? oldScale * scaleBy : oldScale / scaleBy;

    setStageScale(newScale);
    setStagePos({
      x: pointer.x - mousePointTo.x * newScale,
      y: pointer.y - mousePointTo.y * newScale,
    });
  };

  const hoveredCamera = cameras.find(c => c.id === hoveredCameraId);

  return (
    <Card 
      title={
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <LayoutOutlined style={{ color: token.colorPrimary }} />
          <span style={{ color: token.colorText }}>{t("konva.title")}</span>
          <Text type="secondary" style={{ fontSize: 11, marginLeft: 12 }}>
            (Wheel: Zoom | Drag: Pan)
          </Text>
        </div>
      }
      extra={extra}
      size="small"
      style={{ height: "100%", display: "flex", flexDirection: "column", background: token.colorBgContainer }}
      bodyStyle={{ flex: 1, padding: 0, overflow: "hidden" }}
    >
      <div 
        ref={containerRef}
        style={{ height: "100%", background: token.colorBgLayout, position: "relative" }}
      >
        {zones.length > 0 ? (
          <Stage 
            width={dimensions.width} 
            height={dimensions.height}
            onWheel={handleWheel}
            scaleX={stageScale}
            scaleY={stageScale}
            x={stagePos.x}
            y={stagePos.y}
            draggable
            onDragEnd={(e) => setStagePos({ x: e.target.x(), y: e.target.y() })}
          >
            <Layer>
              {/* Background */}
              {mapImage && <KonvaImage image={mapImage} width={baseW} height={baseH} opacity={0.4} />}


              {/* Zones */}
              {zones.map(zone => {
                const isSelected = selectedZoneId === zone.id;
                const levelInfo = LEVEL_MAP[zone.avgLevel];
                return (
                  <React.Fragment key={zone.id}>
                    <Line
                      points={zone.points2D}
                      closed={true}
                      fill={levelInfo.color}
                      opacity={isSelected ? 0.3 : 0.15}
                      stroke={isSelected ? token.colorPrimary : token.colorBorder}
                      strokeWidth={isSelected ? 3 : 1}
                      onClick={() => onZoneSelect(zone.id)}
                      onMouseEnter={(e) => {
                        const s = e.target.getStage();
                        if (s) s.container().style.cursor = "pointer";
                      }}
                      onMouseLeave={(e) => {
                        const s = e.target.getStage();
                        if (s) s.container().style.cursor = "default";
                      }}
                    />
                    <Text
                      x={zone.points2D[0] + 10}
                      y={zone.points2D[1] + 10}
                      text={zone.name}
                      fontSize={12}
                      fill={token.colorTextSecondary}
                      opacity={0.7}
                      fontStyle="bold"
                    />
                  </React.Fragment>
                );
              })}

              {/* Cameras */}
              {cameras.map(cam => {
                const isSelected = selectedCameraId === cam.id;
                const crowdIcon = icons[`crowd_${getStatusKey(cam.level)}`];
                const trIcon = icons[`humantraffic_${getStatusKey(cam.trafficLevel)}`];

                return (
                  <React.Fragment key={cam.id}>
                    {crowdIcon && (
                      <KonvaImage 
                        image={crowdIcon}
                        x={cam.x2d} y={cam.y2d} width={28} height={28}
                        onClick={() => onCameraSelect(cam.id)}
                        onMouseEnter={() => {
                          setHoveredCameraId(cam.id);
                          document.body.style.cursor = "pointer";
                        }}
                        onMouseLeave={() => {
                          setHoveredCameraId(null);
                          document.body.style.cursor = "default";
                        }}
                        shadowBlur={isSelected ? 10 : 0}
                        shadowColor={token.colorPrimary}
                      />
                    )}
                    {trIcon && (
                      <KonvaImage 
                        image={trIcon}
                        x={cam.x2d + 24} y={cam.y2d} width={28} height={28}
                        onClick={() => onCameraSelect(cam.id)}
                        onMouseEnter={() => setHoveredCameraId(cam.id)}
                        onMouseLeave={() => setHoveredCameraId(null)}
                      />
                    )}
                    <Text
                      x={cam.x2d} y={cam.y2d - 15} text={cam.name} fontSize={11}
                      fill={isSelected ? token.colorPrimary : token.colorText}
                      fontStyle={isSelected ? "bold" : "700"}
                      shadowBlur={3}
                      shadowColor={token.colorBgContainer}
                    />
                  </React.Fragment>
                );
              })}

              {/* Tooltip Overlay */}
              {hoveredCamera && (
                <React.Fragment>
                  {/* Tooltip Box Main */}
                  <Rect
                    x={hoveredCamera.x2d + 55}
                    y={hoveredCamera.y2d - 20}
                    width={180}
                    height={95}
                    fill={token.colorBgElevated}
                    stroke={token.colorPrimary}
                    strokeWidth={1}
                    cornerRadius={8}
                    shadowBlur={10}
                    shadowColor="rgba(0,0,0,0.2)"
                    opacity={1}
                  />
                  {/* Tooltip Header Background (Theme Primary) */}
                  <Rect
                    x={hoveredCamera.x2d + 55}
                    y={hoveredCamera.y2d - 20}
                    width={180}
                    height={28}
                    fill={token.colorPrimary}
                    cornerRadius={[8, 8, 0, 0]}
                  />
                  <Text
                    x={hoveredCamera.x2d + 65}
                    y={hoveredCamera.y2d - 12}
                    text={hoveredCamera.name}
                    fontSize={12}
                    fill="#fff"
                    fontStyle="bold"
                  />
                  
                  {/* Tooltip Body */}
                  <Text
                    x={hoveredCamera.x2d + 65}
                    y={hoveredCamera.y2d + 18}
                    text={LEVEL_MAP[hoveredCamera.level].label}
                    fontSize={11}
                    fill={token.colorTextSecondary}
                    fontStyle="700"
                  />
                  <Text
                    x={hoveredCamera.x2d + 65}
                    y={hoveredCamera.y2d + 38}
                    text={`Ppl: ${hoveredCamera.crowdCount} | Traffic: ${hoveredCamera.entryCount + hoveredCamera.exitCount}`}
                    fontSize={11}
                    fill={token.colorPrimary}
                    fontStyle="bold"
                  />
                  
                  {/* Floor Badge Look */}
                  <Rect
                    x={hoveredCamera.x2d + 65}
                    y={hoveredCamera.y2d + 56}
                    width={30}
                    height={16}
                    fill={token.colorPrimary}
                    cornerRadius={4}
                    opacity={0.15}
                  />
                  <Text
                    x={hoveredCamera.x2d + 70}
                    y={hoveredCamera.y2d + 59}
                    text={hoveredCamera.floor || "-"}
                    fontSize={10}
                    fill={token.colorPrimary}
                    fontStyle="bold"
                  />
                  <Text
                    x={hoveredCamera.x2d + 105}
                    y={hoveredCamera.y2d + 59}
                    text={`Gate: ${hoveredCamera.id}`}
                    fontSize={10}
                    fill={token.colorTextTertiary}
                  />
                </React.Fragment>
              )}
            </Layer>
          </Stage>
        ) : (
          <Empty description={t("stats.no_data")} style={{ marginTop: 60 }} />
        )}
      </div>
    </Card>
  );
};

export default CrowdKonvaMap;
