import { useState, useMemo, useEffect } from "react";
import { theme, Button, notification, Tag } from "antd";
import { useI18n } from "@/framework/i18n/hooks";
import { FullscreenOutlined, FullscreenExitOutlined, AlertFilled } from "@ant-design/icons";

// Sub-components
import CrowdVideoMonitor from "./components/CrowdVideoMonitor";
import CrowdOSMMap from "./components/CrowdOSMMap";
import CrowdKonvaMap from "./components/CrowdKonvaMap";
import CrowdStatsChart from "./components/CrowdStatsChart";
import ZoneDetailsModal from "./components/ZoneDetailsModal";
import FloorStatusModal from "./components/FloorStatusModal";

// Mock Data
import { 
  MOCK_SITES,
  MOCK_ZONES, 
  MOCK_CAMERAS, 
  MOCK_HISTORY,
  MOCK_CAMERA_HISTORY,
  generateNextHistoryPoint,
  LEVEL_MAP,
  DensityLevel,
  CrowdHistory
} from "./data/mockData";

const { useToken } = theme;

type GridId = "VIDEO" | "OSM" | "KONVA" | "STATS";

export default function Dashboard() {
  const { token } = useToken();
  const { t } = useI18n(["dashboard", "navigation", "management"]);

  // Hierarchy States
  const [selectedSiteId, setSelectedSiteId] = useState<string | null>("SITE_01");
  const [selectedZoneId, setSelectedZoneId] = useState<string | null>(null);
  const [selectedCameraId, setSelectedCameraId] = useState<number | null>(null);
  
  // Video Grid State
  const [layoutCount, setLayoutCount] = useState<number>(4);
  const [prevLayoutCount, setPrevLayoutCount] = useState<number>(4);
  const [cameraStartIndex, setCameraStartIndex] = useState<number>(0);
  const [prevCameraStartIndex, setPrevCameraStartIndex] = useState<number>(0);
  const [maximizedId, setMaximizedId] = useState<GridId | null>(null);

  // Modal States
  const [isZoneModalVisible, setIsZoneModalVisible] = useState(false);
  const [isFloorModalVisible, setIsFloorModalVisible] = useState(false);

  // Dynamic Zone Status Calculation
  const liveZones = useMemo(() => {
    return MOCK_ZONES.map(zone => {
      const zoneCameras = MOCK_CAMERAS.filter(c => c.zoneId === zone.id);
      const totalPeople = zoneCameras.reduce((sum, c) => sum + c.crowdCount, 0);
      const avgLevel = Math.round(zoneCameras.reduce((sum, c) => sum + c.level, 0) / (zoneCameras.length || 1)) as DensityLevel;
      
      return {
        ...zone,
        totalPeople,
        avgLevel,
        status: (avgLevel >= 5 ? "DANGER" : avgLevel >= 4 ? "WARNING" : avgLevel >= 3 ? "CAUTION" : "NORMAL") as any
      };
    });
  }, []);

  const dangerZones = useMemo(() => liveZones.filter(z => z.avgLevel >= 5), [liveZones]);

  useEffect(() => {
    if (dangerZones.length > 0) {
      const zoneNames = dangerZones.map(z => z.name).join(", ");
      notification.warning({
        message: <span style={{ color: "#fff", fontWeight: 700 }}>{t("alert.notif_title")}</span>,
        description: <span style={{ color: "rgba(255,255,255,0.85)" }}>{t("alert.notif_desc", { zones: zoneNames })}</span>,
        placement: "bottomRight",
        duration: 5,
        icon: <AlertFilled className="blink-icon" style={{ color: token.colorError, fontSize: 24 }} />,
        style: {
          background: "rgba(26, 26, 26, 0.9)",
          backdropFilter: "blur(10px)",
          border: `1px solid ${token.colorError}80`,
          borderRadius: 12,
          boxShadow: `0 8px 32px rgba(0,0,0,0.5), 0 0 15px ${token.colorError}30`,
          padding: "16px 20px"
        },
        closeIcon: <span style={{ color: "#fff", opacity: 0.5 }}>×</span>
      });
    }
  }, [dangerZones, token.colorError, t]);

  // Combined Filtering Logic
  const filteredCameras = useMemo(() => {
    let list = MOCK_CAMERAS;
    if (selectedZoneId) {
      list = list.filter(c => c.zoneId === selectedZoneId);
    } else if (selectedSiteId) {
      list = list.filter(c => c.siteId === selectedSiteId);
    }
    return list;
  }, [selectedSiteId, selectedZoneId]);

  const currentZone = useMemo(() => 
    liveZones.find(z => z.id === selectedZoneId) || null
  , [selectedZoneId, liveZones]);

  const currentSite = useMemo(() => 
    MOCK_SITES.find(s => s.id === selectedSiteId) || MOCK_SITES[0]
  , [selectedSiteId]);

  const [history, setHistory] = useState<CrowdHistory[]>([]);

  // Initialize history when selection changes
  useEffect(() => {
    let initialData: CrowdHistory[] = [];
    if (selectedCameraId) initialData = MOCK_CAMERA_HISTORY(selectedCameraId);
    else if (selectedZoneId) initialData = MOCK_HISTORY(selectedZoneId, false);
    else initialData = MOCK_HISTORY(selectedSiteId || "SITE_01", true);
    
    setHistory(initialData);
  }, [selectedSiteId, selectedZoneId, selectedCameraId]);

  // Update history every minute to simulate real-time data streaming
  useEffect(() => {
    const isSite = !selectedCameraId && !selectedZoneId;
    
    const interval = setInterval(() => {
      setHistory(prev => {
        if (prev.length === 0) return prev;
        
        const nextPoint = generateNextHistoryPoint(isSite);
        
        // Prevent duplicate times (simplified sync check)
        if (prev[prev.length - 1].time === nextPoint.time) {
          return prev;
        }

        // Maintain 60-minute window by sliding old data out
        const nextHistory = [...prev.slice(1), nextPoint];
        return nextHistory;
      });
    }, 60000); // 1-minute interval

    return () => clearInterval(interval);
  }, [selectedSiteId, selectedZoneId, selectedCameraId]);

  const statsTitle = useMemo(() => {
    if (selectedCameraId) {
      const cam = MOCK_CAMERAS.find(c => c.id === selectedCameraId);
      return `${cam?.name} (${t("header.channel")})`;
    }
    if (currentZone) return `${currentZone.name} (${t("sections.camera_control")})`;
    return `${currentSite.name} (${t("header.plant_all")})`;
  }, [selectedCameraId, currentZone, currentSite, t]);

  // Handlers
  const handleCameraSelect = (cameraId: number) => {
    setSelectedCameraId(cameraId);
    const cam = MOCK_CAMERAS.find(c => c.id === cameraId);
    if (cam) {
      // Clear zone filter when selecting a specific camera to allow full channel range
      if (selectedZoneId) {
        setSelectedZoneId(null);
      }
      setSelectedSiteId(cam.siteId);
      
      // Use the full site camera list to find the correct page offset
      const siteCameras = MOCK_CAMERAS.filter(c => c.siteId === cam.siteId);
      const idx = siteCameras.findIndex(c => c.id === cameraId);
      if (idx !== -1) {
        setCameraStartIndex(Math.floor(idx / layoutCount) * layoutCount);
      }
    }
  };

  const handleCameraDoubleClick = (cameraId: number) => {
    const idx = filteredCameras.findIndex(c => c.id === cameraId);
    if (layoutCount > 1) {
      // Zoom In
      setPrevLayoutCount(layoutCount);
      setPrevCameraStartIndex(cameraStartIndex);
      setLayoutCount(1);
      setCameraStartIndex(idx >= 0 ? idx : 0);
      setSelectedCameraId(cameraId);
    } else {
      // Zoom Out (Restore)
      const nextLayout = prevLayoutCount || 4;
      setLayoutCount(nextLayout);
      // Restore previous paging or calculate closest page containing current camera
      if (idx !== -1) {
        setCameraStartIndex(Math.floor(idx / nextLayout) * nextLayout);
      } else {
        setCameraStartIndex(prevCameraStartIndex);
      }
    }
  };

  const handleZoneSelect = (zoneId: string | null) => {
    setSelectedZoneId(zoneId);
    setSelectedCameraId(null);
    setCameraStartIndex(0);
    if (zoneId) {
      const zone = liveZones.find(z => z.id === zoneId);
      if (zone) {
        setSelectedSiteId(zone.siteId);
        setIsZoneModalVisible(true);
      }
    }
    if (layoutCount === 1) setLayoutCount(prevLayoutCount || 4);
  };

  const handleSiteSelect = (siteId: string) => {
    setSelectedSiteId(siteId);
    setSelectedZoneId(null);
    setSelectedCameraId(null);
    setCameraStartIndex(0);
    if (layoutCount === 1) setLayoutCount(prevLayoutCount || 4);
  };

  const toggleMaximize = (id: GridId) => {
    setMaximizedId(prev => (prev === id ? null : id));
  };

  const MaximizeBtn = ({ id }: { id: GridId }) => (
    <Button 
      type="text" 
      size="small" 
      icon={maximizedId === id ? <FullscreenExitOutlined /> : <FullscreenOutlined />} 
      onClick={(e) => { e.stopPropagation(); toggleMaximize(id); }} 
    />
  );

  return (
    <div
      className="crowdsafe-dashboard-root"
      style={{
        height: "100%",
        display: "flex",
        flexDirection: "column",
        background: token.colorBgLayout,
        overflow: "hidden",
        padding: maximizedId ? 0 : 12,
        gap: maximizedId ? 0 : 12,
      }}
    >
      {dangerZones.length > 0 && (
        <div 
          className="risk-ticker-container"
          style={{ 
            background: "#1a1a1a", 
            borderBottom: `2px solid ${token.colorError}`, 
            padding: "8px 16px",
            zIndex: 1000,
            position: "relative",
            boxShadow: "0 4px 15px rgba(0,0,0,0.4)",
            display: "flex",
            alignItems: "center",
            gap: 16,
            flexShrink: 0
          }}
        >
          <Tag color="error" icon={<AlertFilled className="blink-icon" />} style={{ borderRadius: 4, fontWeight: 900 }}>
            {t("alert.urgent")}
          </Tag>
          
          <div style={{ flex: 1, overflow: "hidden", whiteSpace: "nowrap" }}>
            <div className="ticker-text" style={{ color: "#fff", fontSize: 14, display: "inline-block" }}>
              {t("alert.desc", { zones: dangerZones.map(z => z.name).join(", ") })}
            </div>
          </div>

          <div style={{ display: "flex", gap: 8 }}>
            <Button 
              size="small" 
              onClick={() => setIsFloorModalVisible(true)}
              style={{ fontWeight: 600, background: "rgba(255,255,255,0.1)", color: "#fff", borderColor: "rgba(255,255,255,0.3)" }}
            >
              {t("alert.status_btn")}
            </Button>

            <Button 
              size="small" 
              type="primary"
              danger
              onClick={() => handleZoneSelect(dangerZones[0].id)}
              style={{ fontWeight: 600, boxShadow: `0 0 10px ${token.colorError}80` }}
            >
              {t("alert.detail_btn")}
            </Button>
          </div>
        </div>
      )}

      <div 
        className={`dashboard-grid-container ${maximizedId ? "maximized" : ""}`} 
        style={{
          flex: 1,
          display: maximizedId ? "block" : "grid",
          gridTemplateColumns: maximizedId ? "1fr" : "repeat(2, 1fr)",
          gridTemplateRows: maximizedId ? "1fr" : "repeat(2, 1fr)",
          gap: maximizedId ? 0 : 12,
          minHeight: 0,
        }}
      >
        {/* VIDEO */}
        {(!maximizedId || maximizedId === "VIDEO") && (
          <div className="grid-item">
            <CrowdVideoMonitor 
              cameras={filteredCameras} 
              zones={liveZones}
              selectedZoneId={selectedZoneId}
              onZoneSelect={handleZoneSelect}
              layoutCount={layoutCount}
              onLayoutChange={setLayoutCount}
              startIndex={cameraStartIndex}
              onStartIndexChange={setCameraStartIndex}
              selectedCameraId={selectedCameraId}
              onCameraSelect={handleCameraSelect}
              onCameraDoubleClick={handleCameraDoubleClick}
              extra={<MaximizeBtn id="VIDEO" />}
            />
          </div>
        )}

        {/* OSM */}
        {(!maximizedId || maximizedId === "OSM") && (
          <div className="grid-item">
            <CrowdOSMMap 
              sites={MOCK_SITES}
              zones={liveZones} 
              cameras={MOCK_CAMERAS} 
              selectedSiteId={selectedSiteId}
              selectedZoneId={selectedZoneId}
              selectedCameraId={selectedCameraId}
              onSiteSelect={handleSiteSelect}
              onZoneSelect={handleZoneSelect}
              onCameraSelect={handleCameraSelect}
              extra={<MaximizeBtn id="OSM" />}
              isMaximized={!!maximizedId}
            />
          </div>
        )}

        {/* KONVA */}
        {(!maximizedId || maximizedId === "KONVA") && (
          <div className="grid-item">
            <CrowdKonvaMap 
              zones={liveZones} 
              cameras={MOCK_CAMERAS}
              selectedZoneId={selectedZoneId}
              selectedCameraId={selectedCameraId}
              onZoneSelect={handleZoneSelect}
              onCameraSelect={handleCameraSelect}
              extra={<MaximizeBtn id="KONVA" />}
            />
          </div>
        )}

        {/* STATS */}
        {(!maximizedId || maximizedId === "STATS") && (
          <div className="grid-item">
            <CrowdStatsChart 
              history={history} 
              title={statsTitle}
              extra={<MaximizeBtn id="STATS" />}
            />
          </div>
        )}
      </div>

      <style>{`
        .crowdsafe-dashboard-root { box-sizing: border-box; transition: all 0.3s ease; position: relative; }
        .grid-item { min-width: 0; min-height: 0; height: 100%; }
        .dashboard-grid-container.maximized { width: 100% !important; min-height: 0; }
        
        .blink-icon { animation: blink 1s infinite; }
        @keyframes blink { 
          0% { opacity: 1; } 
          50% { opacity: 0.3; } 
          100% { opacity: 1; } 
        }

        .ticker-text {
          animation: marquee 20s linear infinite;
          padding-left: 20px;
        }
        @keyframes marquee {
          0% { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }

        .risk-ticker-container:hover .ticker-text {
          animation-play-state: paused;
        }

        @media (max-width: 1200px) {
          .dashboard-grid-container:not(.maximized) {
            grid-template-columns: 1fr !important;
            grid-template-rows: auto !important;
            overflow-y: auto !important;
            display: flex !important;
            flex-direction: column !important;
            gap: 16px !important;
          }
          .grid-item { height: ${maximizedId ? "100%" : "450px"} !important; flex-shrink: 0; }
        }
      `}</style>

      <ZoneDetailsModal 
        zone={currentZone} 
        visible={isZoneModalVisible} 
        onClose={() => setIsZoneModalVisible(false)} 
      />
      <FloorStatusModal
        zones={liveZones}
        visible={isFloorModalVisible}
        onClose={() => setIsFloorModalVisible(false)}
      />
    </div>
  );
}
